// Claim a file from incoming/ -> processing/ AND fingerprint it (sha256+size+MIME) in one node.
// fs.renameSync is atomic, so the rename doubles as a lock: two runs race -> exactly one wins.
// Webhook: body.fileName names the file. Schedule: no name -> scan for the oldest STABLE file.
const fs = require('fs');
const crypto = require('crypto');
const cfg = $('Config').first().json;
const INCOMING = cfg.docRoot + '/incoming';
const PROCESSING = cfg.docRoot + '/processing';
const STABLE_MS = 5000;
const MIME = { pdf: 'application/pdf', png: 'image/png', jpg: 'image/jpeg', jpeg: 'image/jpeg', tif: 'image/tiff', tiff: 'image/tiff', bmp: 'image/bmp', webp: 'image/webp' };

const j = ($input.all()[0] || {}).json || {};
const target = (j.body && j.body.fileName) || j.fileName || null;

function claim(name) {
  const dst = PROCESSING + '/' + name;
  try { fs.renameSync(INCOMING + '/' + name, dst); }
  catch (e) { return null; }
  const buf = fs.readFileSync(dst);
  const ext = (name.split('.').pop() || '').toLowerCase();
  return {
    fileName: name,
    claimedPath: dst,
    file_hash: crypto.createHash('sha256').update(buf).digest('hex'),
    file_size: buf.length,
    mime_type: MIME[ext] || 'application/octet-stream',
  };
}

if (target) {
  const c = claim(target);
  return c ? [{ json: c }] : [];
}

let names = [];
try { names = fs.readdirSync(INCOMING); } catch (e) { return []; }
names.sort();
const now = Date.now();
for (const name of names) {
  if (name.startsWith('.')) continue;
  let st;
  try { st = fs.statSync(INCOMING + '/' + name); } catch (e) { continue; }
  if (!st.isFile()) continue;
  if (now - st.mtimeMs < STABLE_MS) continue;
  const c = claim(name);
  if (c) return [{ json: c }];
}
return [];

// Split the OCR text into ~1500-char chunks (under BGE's 512-token limit) for embedding.
const text = $('OCR (Document Inference)').first().json.text || '';
const size = 1500;
const out = [];
for (let i = 0; i < text.length; i += size) {
  out.push({ json: {
    chunk: text.slice(i, i + size),
    chunk_index: out.length,
    source_file: $('Claim File').first().json.fileName,
    decision: $('OpenVINO Agent').first().json.decision,
  }});
}
return out;

// Success: move processing/ -> processed/ (atomic, idempotent).
const fs = require('fs');
const cfg = $('Config').first().json;
const name = $('Claim File').first().json.fileName;
try { fs.renameSync(cfg.docRoot + '/processing/' + name, cfg.docRoot + '/processed/' + name); } catch (e) {}
return [{ json: { moved: name, to: 'processed' } }];

// Fallback (unexpected agent decision): move processing/ -> failed/ for human attention. Idempotent.
const fs = require('fs');
const cfg = $('Config').first().json;
const name = $('Claim File').first().json.fileName;
try { fs.renameSync(cfg.docRoot + '/processing/' + name, cfg.docRoot + '/failed/' + name); } catch (e) {}
return [{ json: { moved: name, to: 'failed' } }];

// Not a processable document (CLIP triage rejected it). Move to a VISIBLE rejected/ folder so the
// user can find and re-submit it - never a silent drop. Returns a clean 'rejected' result.
const fs = require('fs');
const cfg = $('Config').first().json;
const name = $('Claim File').first().json.fileName;
const c = $('OpenVINO Model Server').first().json;
try { fs.renameSync(cfg.docRoot + '/processing/' + name, cfg.docRoot + '/rejected/' + name); } catch (e) {}
return [{ json: {
  decision: 'rejected',
  document_type: 'not_a_document',
  summary: 'Not a processable document (' + (c.best_label || 'non-document') + ', P(doc)=' + (c.confidence != null ? c.confidence : '') + ')',
  moved: name, to: 'rejected'
}}];
